import React from 'react';
import { Box, Card, CardContent, Stack, Typography } from '@mui/material';

export interface TabHeaderProps {
    icon?: React.ReactNode;
    title: string;
    subtitle?: string;
    action?: React.ReactNode;
}

/**
 * Header card shown inside a tab's body (under the tab strip), matching the
 * `PageContainer` look. Use this when the page lives inside a `PageTabs` shell
 * so each tab can announce its own context. For standalone pages, prefer
 * `PageContainer` directly.
 */
export const TabHeader: React.FC<TabHeaderProps> = ({ icon, title, subtitle, action }) => (
    <Card variant="outlined" sx={{ borderRadius: 2, mb: 2 }}>
        <CardContent sx={{ '&:last-child': { pb: 2 } }}>
            <Stack
                direction="row"
                spacing={1.5}
                sx={{ alignItems: 'flex-start', justifyContent: 'space-between' }}
            >
                <Box sx={{ minWidth: 0 }}>
                    {(title || icon) && (
                        <Stack
                            direction="row"
                            spacing={1.5}
                            sx={{ alignItems: 'center', mb: subtitle ? 0.5 : 0 }}
                        >
                            {icon}
                            {title && (
                                <Typography variant="h5" sx={{ fontWeight: 700 }}>
                                    {title}
                                </Typography>
                            )}
                        </Stack>
                    )}
                    {subtitle && (
                        <Typography variant="body2" color="text.secondary">
                            {subtitle}
                        </Typography>
                    )}
                </Box>
                {action && <Box sx={{ flexShrink: 0 }}>{action}</Box>}
            </Stack>
        </CardContent>
    </Card>
);
